import { Card, Stack, Row, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}: Props) {
  const resolvedUnit = unit ?? 'C';
  const visibleForecast = forecast.slice(0, 5);

  const conditionText = condition ?? '';
  const lowerCondition = conditionText.toLowerCase();

  const derivedConditionIcon =
    lowerCondition.includes('☀️') ||
    lowerCondition.includes('☁️') ||
    lowerCondition.includes('🌧️') ||
    lowerCondition.includes('⛈️') ||
    lowerCondition.includes('❄️') ||
    lowerCondition.includes('🌫️') ||
    lowerCondition.includes('🌤️')
      ? conditionText
      : lowerCondition.includes('sunny') || lowerCondition.includes('clear')
      ? '☀️'
      : lowerCondition.includes('cloudy') || lowerCondition.includes('overcast')
      ? '☁️'
      : lowerCondition.includes('rainy') || lowerCondition.includes('drizzle')
      ? '🌧️'
      : lowerCondition.includes('storm') || lowerCondition.includes('thunder')
      ? '⛈️'
      : lowerCondition.includes('snow')
      ? '❄️'
      : lowerCondition.includes('mist') || lowerCondition.includes('fog')
      ? '🌫️'
      : '🌤️';

  return (
    <Card
      padding={24}
      shadow="md"
      border={true}
      role="region"
      aria-label={`Weather for ${city}`}
      style={{
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        <Row justify="between" align="center">
          <Text
            variant="h3"
            weight="semibold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {city}
          </Text>
          <Text
            variant="caption"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            °{resolvedUnit}
          </Text>
        </Row>

        <Stack direction="vertical" gap={8}>
          <Text
            variant="h1"
            weight="bold"
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {temperature}°
          </Text>
          <Row align="center" gap={8}>
            <Text variant="body" color="var(--ggui-color-primary-600, #0284c7)">
              {derivedConditionIcon}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Row>
        </Stack>

        <Row justify="between" gap={16} wrap={true}>
          <Stack direction="vertical" gap={2}>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text
              variant="body"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
          </Stack>

          <Stack direction="vertical" gap={2}>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind
            </Text>
            <Text
              variant="body"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} km/h
            </Text>
          </Stack>
        </Row>

        <Divider
          style={{ borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)' }}
        />

        {visibleForecast.length === 0 ? (
          <Row justify="between" gap={8} wrap={false}>
            <Box
              style={{
                flex: 1,
                background: 'var(--ggui-color-surface, #fafafa)',
                border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                padding: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                No forecast data
              </Text>
            </Box>
          </Row>
        ) : (
          <Row justify="between" gap={8} wrap={false}>
            {visibleForecast.map((item, index) => {
              const day = item.day ?? '-';
              const icon = item.icon ?? '🌤️';
              const high = item.high ?? '--';
              const low = item.low ?? '--';

              return (
                <Box
                  key={item.day ?? index}
                  style={{
                    flex: 1,
                    minWidth: 0,
                    background: 'var(--ggui-color-surface, #fafafa)',
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    padding: 'var(--ggui-spacing-2, 8px)',
                  }}
                >
                  <Stack direction="vertical" gap={4} align="center">
                    <Text
                      variant="caption"
                      weight="medium"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {day}
                    </Text>
                    <Text
                      variant="body"
                      color="var(--ggui-color-primary-600, #0284c7)"
                    >
                      {icon}
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      H:{high}° L:{low}°
                    </Text>
                  </Stack>
                </Box>
              );
            })}
          </Row>
        )}
      </Stack>
    </Card>
  );
}
